import{_ as o,o as t,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const u="/images/uebung062.jpg",k=JSON.parse('{"title":"Übung Lektion 37","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung37.md","filePath":"lektionen/uebung37.md"}'),l={name:"lektionen/uebung37.md"};function p(r,e,s,a,c,b){return t(),i("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-37" tabindex="-1">Übung Lektion 37 <a class="header-anchor" href="#ubung-lektion-37" aria-label="Permalink to &quot;Übung Lektion 37&quot;">​</a></h1><p>A) Beantworten Sie folgende Fragen auf Sanskrit mit Hilfe der in Klammern angegebenen Wörter. Übersetzen Sie die Fragesätze.</p><p>Beispiel: क आगच्छति (राम) । » राम आगच्छति ।</p><p>कस्मै ब्राह्मण्यन्नं ददौ ॥१॥ (भिक्षु, बाला, दास, भगवन्त्)</p><blockquote><p>भिक्षवे । भिक्षुभ्यो । बालायै । बालाभ्यो । दासाय । दासेभ्यो । भगवते । भगद्भ्यो  ब्राह्मण्यन्नं ददौ ॥१॥</p></blockquote><p>क आर्यसत्यान्यजानात् ॥२॥ (बुद्ध, शाक्यमुनि)</p><blockquote><p>बुद्ध आर्यसत्यान्यजानात् । शाक्यमुनिरार्यसत्यान्यजानात् ॥२॥</p></blockquote><p>कुत्राग्निश्चीयते ॥३॥ (यज्ञस्थान, मही)</p><blockquote><p>यज्ञस्थाने ऽग्निश्चीयते । मह्यामग्निश्चीयते ॥३॥</p></blockquote><p>कदा ब्राह्माणा घृतमग्नौ जुह्वति ॥४॥ (यज्ञकाल, देवान् स्तु &lt;Absolutiv&gt;)</p><blockquote><p>यज्ञकले ब्राह्माणा घृतमग्नौ जुह्वति । देवान्स्तुत्वा ब्राह्माणा घृतमग्नौ जुह्वति ॥४॥</p></blockquote><p>कस्मान्मतिमतयः पुण्यं चक्रुः ॥५॥ (स्वर्गलोभ, नरकभय, भीतनरकता)</p><blockquote><p>स्वर्गलोभान्मतिमतयः पुण्यं चक्रुः । नरकभयान्मतिमतयः पुण्यं चक्रुः । भीतनरकताया मतिमतयः पुण्यं चक्रुः ॥५॥</p></blockquote><p>किमेव शस्त्रं छिनत्ति ॥६॥ (शरीर, अजीव)</p><blockquote><p>शरीरमेव शस्त्रं छिनत्ति । अजीवमेव शस्त्रं छिनत्ति ॥६॥</p></blockquote><p>किंकामः शत्रुरार्यैः सह युयुधे ॥७॥ (धनं जि)</p><blockquote><p>धनं जेतुकामः शत्रुरार्यैः सह युयुधे ॥७॥</p></blockquote><p>कया भिक्षुरादितः ॥८॥ (गुणवती शूद्रा)</p><blockquote><p>गुणवत्या शूद्रया भिक्षुरादितः ॥७॥</p></blockquote><p>कुतः सुपुनर्भवं गम्यते ॥९॥ (कृतपुण्यत्व, सुनीति)</p><blockquote><p>कृतपुण्यत्वात्सुपुनर्भवं गम्यते । सुनीतेः । सुनीत्याः । सुनीतितः सुपुनर्भवं गम्यते ॥९॥</p></blockquote><p>केन शूद्रा न काम्येत ॥१०॥ (द्विजाति, ब्राह्मण, साधु)</p><blockquote><p>द्विजातिना । ब्राह्मणेन । साधुना शूद्रा न काम्येत ॥१०॥</p></blockquote><p>किमर्थं सुगतो ऽगारादनगार्यं प्रवव्राज ॥११॥ (दुःखमोक्ष, मोक्षनयन्ती प्रज्ञा)</p><blockquote><p>दुःखमोक्षस्यार्थं । दुःखमोक्षार्थं सुगतो ऽगारादनगार्यं प्रवव्राज । मोक्षनयन्त्याः प्रज्ञाया अर्थं सुगतो ऽगारादनगार्यं प्रवव्राज ॥११॥</p></blockquote><p>कस्याः पुत्रः कृष्ण आसीत् ॥१२॥ (देवकी)</p><blockquote><p>देवक्याः पुत्रः कृष्ण आसीत् ॥१२॥</p></blockquote><p>क्व मर्तुं सज्जना इच्छन्ति ॥१३॥ (काशी = वाराणसी)</p><blockquote><p>काश्यां । वाराणस्यां मर्तुं सज्जना इच्छन्ति ॥१३॥</p></blockquote><p>केषां धर्मो वेदाध्ययनम् ॥१४॥ (द्विज, द्विजाति, आर्य)</p><blockquote><p>द्विजानां । द्विजातीनां । आर्याणां धर्मो वेदाध्ययनम् ॥१४॥</p></blockquote><p>कैर्वेदः प्रोक्तः ॥१५॥ (ऋषि)</p><blockquote><p>ऋषिभिर्वेदः प्रोक्तः ॥१५॥</p></blockquote><p>कस्मिञ्जात आर्यः सुखमाप्नोति ॥१६॥ (पुत)</p><blockquote><p>पुत्रे जात आर्यः सुखमाप्नोति ॥१६॥</p></blockquote><p>का नरा लुभ्यन्ति ॥१७॥ (सुरूपशरीरा, देवीरूपा)</p><blockquote><p>सुरूपशरीरा । देवीरूपा नरा लुभ्यन्ति ॥१७॥</p></blockquote><p>के नराः सुरूपा लुभ्यन्ति ॥१८॥ (समोह, बुद्धिमन्त्)</p><blockquote><p>समोहा । बुद्धिमन्तो नराः सुरूपा लुभ्यन्ति ॥१८॥</p></blockquote><p>कस्या इन्द्रः पुत्रं दास्यति ॥१९॥ (कृतव्रता पुण्यवती सुमतिब्राह्मणी)</p><blockquote><p>कृतव्रतायै पुण्यवतै सुमतये । सुमत्यै । ब्राह्मण्या इन्द्रः पुत्रं दास्यति । ... ब्राह्मण्यायिन्द्रः पुत्रं दास्यति ॥१९॥</p></blockquote><p>B) Übersetzen Sie:</p><p>किं स्थितप्रज्ञः प्रव्रजेत्किमगारे पुत्रेषु वसेत् ॥१॥</p><blockquote><p>Soll jemand, des Einsicht festgegründet ist, in die Heimlosigkeit gehen oder soll er daheim bei seinen Söhnen bleiben?</p></blockquote><p>अपि गुरुः सत्यं जानाति ॥२॥</p><blockquote><p>Kennt der Meister auch die Wahrheit?</p></blockquote><p>कच्चिच्छुद्रा द्विजदासाः ॥३॥</p><blockquote><p>Ist der Śūdra Leibeigener der Zweimalgeborenen?</p></blockquote><p>कच्छिच्छुद्रो भारमाबिभः ॥४॥</p><blockquote><p>Hat der Śūdra die Last gebracht?</p></blockquote><p>C) Übersetzen Sie folgende अव्ययीभाव :</p><p>1. अति Postposition mit Akk.: &quot;über ... hinaus&quot;</p><ol><li>अतिमात्रम् । मात्रामतीत्य &quot;jenseits eines Maßes, übermäßig&quot;</li><li>अतिवसन्तम् । वसन्तमतीत्य &quot;nach dem Frühling&quot;</li></ol><p>2. अधि &quot;in&quot;</p><ol><li>अधिहरि &quot;in Hari&quot;</li><li>अधिकेरलम् &quot;in Kerala&quot;</li></ol><p>3. अनु &quot;entsprechend, entlang, nach&quot;</p><ol><li>अनुरूपम् &quot;entsprechend&quot;</li><li>अनुदिनम् &quot;täglich&quot;</li><li>अनुगङ्गम् &quot;entlang des Ganges&quot;</li><li>अनुविष्णुम् &quot;nach Viṣṇu&quot;</li></ol><p>4. अप &quot;ohne&quot;</p><ol><li>अपविष्णुम् &quot;ohne Viṣṇu&quot;</li></ol><p>5. अभि &quot;in Richtung auf&quot;</p><ol><li>अभिमुखम् &quot;vorn, gegenüber&quot;</li><li>अभ्यग्नि &quot;zum Feuer&quot;</li></ol><p>6. आ &quot;seit, bis, einschließlich&quot;</p><ol><li>आबालवृद्धम् &quot;einschließlich Kinder und Greise&quot;</li><li>आमरणम् &quot;bis zum Tod&quot;</li></ol><p>. उप &quot;nahe&quot;</p><ol><li>उपवृक्षम् &quot;in der Nähe des Baums&quot;</li></ol><p>8. यथा</p><ol><li>यथास्थानम् &quot;am rechten Ort&quot;</li></ol><p><img src="'+u+'" alt=""><br> Abb.: पुत्रे जात आर्यः सुखमाप्नोति<br> [Bildquelle: <a href="mailto:amee@work" target="_blank" rel="noreferrer">amee@work</a>. -- <a href="http://www.flickr.com/photos/amee_photo/3122658519/in/photostream/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/amee_photo/3122658519/in/photostream/</a>. -- Zugriff am 2009-01-20. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Übersetzen Sie ins Sanskrit indem Sie ausschließlich Verbformen des Perfekt verwenden:</p><p>Als einmal irgendein Greis in ein anderes Dorf ging, ermüdete er unterwegs. Da ging er, um sich auszuruhen, zum Fuß eines an der Seite stehenden Mangobaums. Auf diesem Baum gab es reife Früchte. Der Greis bekam Lust auf diese. Aber er konnte nicht auf den Baum steigen und nach den Früchten greifen. Zum Glück waren auf diesem Baum irgendwelche Affen, die Früchte fraßen. Als er diese erblickte, freute sich der Greis. Was tat er? Er nahm einige Steine, zielte auf die Affen und warf. Die erbosten Affen pflückten irgendwelche Früchte und warfen sie auf den Greis. Der Greis nahm diese erfreut und ging in seine gewünschte Gegend. Siehe, das Geschick des Greises!</p><p>एकदा कश्चिद्वृद्धो ग्रामान्तरं गच्छन्पथि श्रान्तो ऽभवत् । अतः स विश्रमाय पार्श्वस्थितस्य चूततरोर्मूलमगच्छत् ॥ तस्मिन्वृक्षे पचेलिमानि फलान्यवर्तन्त । वृद्धस्य तेषु स्पृहा जाता । परं स वृक्षमारुह्य तानि ग्रहीतुं नाशक्नोत् ॥ दिष्ट्या तस्मिन् तरौ केचिद्वानराः फलानि खादन्तः स्थिताः । तानवलोक्य वृद्धः प्रहर्षं गतः । स किमकरोत् । स कतिचिदुपलानादाय वानरांल्लक्ष्यीकृत्य प्राक्षिपत् । वानराः कुपिताः कानिचित्फलान्यवचित्य वृद्धं प्रति प्राक्षिपन् । वृद्धः सहर्षं तान्यादाय स्वाभीष्टदेशं गतः ॥ अहो वृद्धस्य कौशलम् ॥</p>',72)])])}const d=o(l,[["render",p]]);export{k as __pageData,d as default};
